function replaceNodeAndRebind(node,binder){
  if(!node||!node.parentNode)return node;
  var clone=node.cloneNode(true);
  try{
    if('value' in node)clone.value=node.value;
    if('checked' in node)clone.checked=node.checked;
    if('selectedIndex' in node)clone.selectedIndex=node.selectedIndex;
  }catch(error){}
  node.parentNode.replaceChild(clone,node);
  if(typeof binder==='function')binder(clone);
  return clone;
}

